+    console.log('\n--- Round-trip Tests ---');
+
+    function roundTrip(obj) {
+        const str = qs.stringify(obj);
+        const parsed = qs.parse(str);
+        return JSON.stringify(parsed);
+    }
+
+    // Simple object
+    const rt1 = { a: '1', b: '2' };
+    const rt1Parsed = qs.parse(qs.stringify(rt1));
